import React, { useState } from "react";
import "./Dashboard.css";

export default function Dashboard({ employee }) {
  const [view, setView] = useState('home');

  if (view === 'home') {
    return (
      <div className="dash-wrapper" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
        {/* PRASA LOGO & PORTAL NAME */}
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: 24 }}>
          <img src="/logo.png" alt="PRASA Logo" style={{ height: 64, width: 64, objectFit: 'contain', background: '#fff', borderRadius: 16, marginBottom: 12 }} />
          <span style={{ fontSize: 32, fontWeight: 700, color: '#0f9d58', letterSpacing: 1 }}>PRASA Employee Portal</span>
        </div>
        {/* Welcome line */}
        <div style={{ fontSize: 22, color: '#222', marginBottom: 32, fontWeight: 500 }}>
          Welcome{employee?.empName ? `, ${employee.empName}` : ''}!
        </div>
        {/* Profile and Settings menu boxes */}
        <div style={{ display: 'flex', gap: 32 }}>
          <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}
            onClick={() => setView('dashboard')}
          >
            Profile
          </div>
          <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
            Settings
          </div>
        </div>
      </div>
    );
  }

  if (view === 'dashboard') {
    return (
      <div className="dash-wrapper" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: 24 }}>
          <img src="/logo.png" alt="PRASA Logo" style={{ height: 64, width: 64, objectFit: 'contain', background: '#fff', borderRadius: 16, marginBottom: 12 }} />
          <span style={{ fontSize: 32, fontWeight: 700, color: '#0f9d58', letterSpacing: 1 }}>PRASA Employee Portal</span>
        </div>
        <div style={{ fontSize: 22, color: '#222', marginBottom: 32, fontWeight: 500 }}>
          Dashboard
        </div>
        <div style={{ display: 'flex', gap: 32 }}>
          <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
            Add New
          </div>
          <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
            History
          </div>
          <div style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', transition: 'border 0.2s, box-shadow 0.2s' }}>
            Tools
          </div>
        </div>
      </div>
    );
  }
}
